    const map = new Map();

    // Group points by their y-coordinate
    for (const [x, y] of points) {
        if (!map.has(y)) {
            map.set(y, []);
        }
        map.get(y).push(x);
    }

    const yKeys = Array.from(map.keys());
    const yCount = yKeys.length;

    let result = 0;

    // For each pair of y-coordinates, find the number of ways to form a trapezoid
    for (let i = 0; i < yCount; i++) {
        const y1 = yKeys[i];
        const xs1 = map.get(y1);
        const len1 = xs1.length;

        for (let j = i + 1; j < yCount; j++) {
            const y2 = yKeys[j];
            const xs2 = map.get(y2);
            const len2 = xs2.length;

            // For each pair of x-coordinates in the two y-levels, count the number of trapezoids
            for (let k = 0; k < len1; k++) {
                const x1 = xs1[k];
                for (let l = 0; l < len2; l++) {
                    const x2 = xs2[l];
                    // The number of ways to choose two points from the first y-level
                    const ways1 = (len1 - 1) * (len1 - 2) / 2;
                    // The number of ways to choose two points from the second y-level
                    const ways2 = (len2 - 1) * (len2 - 2) / 2;
                    result = (result + ways1 * ways2) % MOD;
                }
            }
        }
    }

    return result;
}

